14	
15	// A module that assembles RVVInstructions into RVVCmd before storing into the
16	// RVVInstructionQueue. It's also responsible for handling architectural
17	// configuration state (ie. LMUL, SEW). Inputs to this module maybe unaligned
18	// (ie [invalid, valid, valid, invalid]) while outputs will always be aligned
19	// (ie [valid, valid, invalid, invalid]).
20	// Arguments from the scalar register file (for vx or configuration
21	// instructions) arrive one cycle after the Instruction is dispatched, so this
22	// module introduces one cycle of latency before putting the command into the
23	// queue.
24	module RvvFrontEnd#(parameter N = 4,
25	                    parameter CAPACITYBITS=$clog2(2*N + 1),
26	                    parameter REDUCE_LMUL = 1)
27	(
28	  input clk,
29	  input rstn,
30	
31	  input logic [`VSTART_WIDTH-1:0]     vstart_i,
32	  input logic [`VCSR_VXRM_WIDTH-1:0]  vxrm_i,
33	  input logic [`VCSR_VXSAT_WIDTH-1:0] vxsat_i,
34	  input logic [2:0]                   frm_i,
35	
36	  // Instruction input.
37	  input logic [N-1:0] inst_valid_i,
38	  input RVVInstruction [N-1:0] inst_data_i,
39	  output logic [N-1:0] inst_ready_o,
40	
41	  // Register file input
42	  input logic [(2*N)-1:0] reg_read_valid_i,
43	  input logic [(2*N)-1:0][31:0] reg_read_data_i,
44	
45	  // Floating point register file input (scalar rs1 for OPFVF instructions).
46	  input logic [N-1:0][31:0] freg_read_data_i,
47	
48	  // Scalar Regfile writeback for configuration functions.
49	  output logic [N-1:0] reg_write_valid_o,
50	  output logic [N-1:0][4:0] reg_write_addr_o,
51	  output logic [N-1:0][31:0] reg_write_data_o,
52	
53	  // Command output.
54	  output logic [N-1:0] cmd_valid_o,
55	  output RVVCmd [N-1:0] cmd_data_o,
56	  input logic [CAPACITYBITS-1:0] queue_capacity_i,  // Number of elements that can be enqueued
57	  output logic [CAPACITYBITS-1:0] queue_capacity_o,
58	
59	  // Trap output.
60	  output logic trap_valid_o,
61	  output RVVInstruction trap_data_o,
62	
63	  // Config state
64	  output config_state_valid,
65	  output RVVConfigState config_state
66	);
67	  localparam COUNTBITS = $clog2(N + 1);
68	  typedef logic [COUNTBITS-1:0] count_t;
69	
70	  // vtype architectural state
71	  logic vill;
72	  RVVConfigState config_state_q;
73	
74	  // Instructions to assemble into commands
75	  logic [N-1:0] valid_inst_q;     // If the instruction in this slot is valid
76	  count_t valid_inst_count_q;     // The sum of valid_inst_q
77	  RVVInstruction inst_q [N-1:0];  // The instruction in the slot
78	
79	  // Backpressure
80	  count_t valid_in_psum [N:0];
81	  always_comb begin
82	    valid_in_psum[0] = 0;
83	    for (int i = 0; i < N; i++) begin
84	      valid_in_psum[i+1] = valid_in_psum[i] + inst_valid_i[i];
85	    end
86	  end
87	
88	  // State, for time being lets do not state forwarding for timing
89	  logic config_state_reduction;
90	  always_comb begin
91	    config_state_reduction = 1;
92	    for (int i = 0; i < N; i++) begin
93	      config_state_reduction = config_state_reduction & (!valid_inst_q[i]);
94	    end
95	  end
96	  assign config_state_valid = config_state_reduction;
97	  assign config_state = config_state_q;
98	
99	  logic [CAPACITYBITS-1:0] queue_capacity;
100	  assign queue_capacity_o = queue_capacity;
101	  always_comb begin
102	    queue_capacity = queue_capacity_i - valid_inst_count_q;
103	  end
104	
105	  logic inst_accepted [N-1:0];
106	  count_t valid_inst_count_d;
107	  always_comb begin
108	    for (int i = 0; i < N; i++) begin
109	      inst_accepted[i] = (valid_in_psum[i] < queue_capacity) && inst_valid_i[i];
110	      inst_ready_o[i] = inst_accepted[i];
111	    end
112	    valid_inst_count_d = (valid_in_psum[N] < queue_capacity) ?
113	        valid_in_psum[N] : queue_capacity;
114	  end
115	
116	  always_ff @(posedge clk or negedge rstn) begin
117	    if (!rstn) begin
118	      for (int i = 0; i < N; i++) begin
119	        valid_inst_q[i] <= 0;
120	        valid_inst_count_q <= 0;
121	      end;
122	    end else begin
123	      for (int i = 0; i < N; i++) begin
124	        valid_inst_q[i] <= inst_accepted[i];
125	        valid_inst_count_q <= valid_inst_count_d;
126	      end
127	    end
128	  end
129	
130	  always_ff @(posedge clk) begin
131	    for (int i = 0; i < N; i++) begin
132	      inst_q[i] <= inst_accepted[i] ? inst_data_i[i] : inst_q[i];
133	    end
134	  end
135	
136	  // Update configuration architectural state
137	  RVVConfigState inst_config_state [N:0];
138	  logic [31:0] avl [N-1:0];
139	  logic [31:0] vlmax [N-1:0];
140	  logic is_setvl [N-1:0];
141	  logic [`VL_WIDTH-1:0] vl_minus_one [N-1:0];
142	  always_comb begin
143	    inst_config_state[0] = config_state_q;
144	    inst_config_state[0].vstart = vstart_i;
145	    inst_config_state[0].xrm = RVVXRM'(vxrm_i);
146	    inst_config_state[0].xsat = vxsat_i;
147	`ifdef ZVE32F_ON
148	    inst_config_state[0].frm = RVFRM'(frm_i);
149	`endif  // ZVE32F_ON
150	    for (int i = 0; i < N; i++) begin
151	      inst_config_state[i+1] = inst_config_state[i];
152	      avl[i] = 0;
153	      vlmax[i] = 0;
154	      is_setvl[i] = 0;
155	
156	      if (valid_inst_q[i] &&
157	          (inst_q[i].opcode == RVV) &&
158	          (inst_q[i].bits[7:5] == 3'b111)) begin
159	        if (inst_q[i].bits[24] == 0) begin  // vsetvli
160	          // Set AVL based on encoding (see Section 6.2 of RVV spec)
161	          unique case (inst_q[i].bits[12:8])
162	            0: unique case (inst_q[i].bits[4:0])
163	              0:  avl[i] = inst_config_state[i].vl;  // rd = x0, rs1 = x0
164	              default: avl[i] = 32'hFFFFFFFF;        // rd != x0, rs1 = x0
165	            endcase
166	            default: avl[i] = reg_read_data_i[2*i];  // rs1 != x0
167	          endcase
168	
169	          inst_config_state[i+1].lmul_orig = RVVLMUL'(inst_q[i].bits[15:13]);
170	          inst_config_state[i+1].sew = RVVSEW'(inst_q[i].bits[18:16]);
171	          inst_config_state[i+1].ta = inst_q[i].bits[19];
172	          inst_config_state[i+1].ma = inst_q[i].bits[20];
173	          is_setvl[i] = 1;
174	        end else if (inst_q[i].bits[24:23] == 2'b11) begin  // vsetivli
175	          avl[i] =
176	              {{(`VL_WIDTH - 5){1'b0}}, inst_q[i].bits[12:8]};
177	          inst_config_state[i+1].lmul_orig = RVVLMUL'(inst_q[i].bits[15:13]);
178	          inst_config_state[i+1].sew = RVVSEW'(inst_q[i].bits[18:16]);
179	          inst_config_state[i+1].ta = inst_q[i].bits[19];
180	          inst_config_state[i+1].ma = inst_q[i].bits[20];
181	          is_setvl[i] = 1;
182	        end else if (inst_q[i].bits[24:23] == 2'b10) begin  // vsetvl
183	          // Set AVL based on encoding (see Section 6.2 of RVV spec)
184	          unique case (inst_q[i].bits[12:8])
185	            0: unique case (inst_q[i].bits[4:0])
186	              0:  avl[i] = inst_config_state[i].vl;  // rd = x0, rs1 = x0
187	              default: avl[i] = 32'hFFFFFFFF;        // rd != x0, rs1 = x0
188	            endcase
189	            default: avl[i] = reg_read_data_i[2*i];  // rs1 != x0
190	          endcase
191	          inst_config_state[i+1].lmul_orig =
192	              RVVLMUL'(reg_read_data_i[(2*i) + 1][2:0]);
193	          inst_config_state[i+1].sew =
194	              RVVSEW'(reg_read_data_i[(2*i) + 1][5:3]);
195	          inst_config_state[i+1].ta = reg_read_data_i[(2*i) + 1][6];
196	          inst_config_state[i+1].ma = reg_read_data_i[(2*i) + 1][7];
197	          is_setvl[i] = 1;
198	        end
199	      end
200	
201	      if (is_setvl[i]) begin
202	        // Compute legality of vtype.
203	        unique case (inst_config_state[i+1].sew)
204	          SEW8:
205	            unique case(inst_config_state[i+1].lmul_orig)
206	              LMULRESERVED: inst_config_state[i+1].vill = 1;
207	              LMUL1_8: inst_config_state[i+1].vill = 1;
208	              default: inst_config_state[i+1].vill = 0;
209	            endcase
210	          SEW16:
211	            unique case(inst_config_state[i+1].lmul_orig)
212	              LMULRESERVED: inst_config_state[i+1].vill = 1;
213	              LMUL1_8: inst_config_state[i+1].vill = 1;
214	              LMUL1_4: inst_config_state[i+1].vill = 1;
215	              default: inst_config_state[i+1].vill = 0;
216	            endcase
217	          SEW32:
218	            unique case(inst_config_state[i+1].lmul_orig)
219	              LMULRESERVED: inst_config_state[i+1].vill = 1;
220	              LMUL1_8: inst_config_state[i+1].vill = 1;
221	              LMUL1_4: inst_config_state[i+1].vill = 1;
222	              LMUL1_2: inst_config_state[i+1].vill = 1;
223	              default: inst_config_state[i+1].vill = 0;
224	            endcase
225	          default: inst_config_state[i+1].vill = 1;
226	        endcase
227	
228	        // Compute vl to set (saturating with necessary)
229	        unique case (inst_config_state[i+1].lmul_orig)
230	          LMUL1_8: vlmax[i] = ((`VLENB)/8) >> inst_config_state[i+1].sew;
231	          LMUL1_4: vlmax[i] = ((`VLENB)/4) >> inst_config_state[i+1].sew;
232	          LMUL1_2: vlmax[i] = ((`VLENB)/2) >> inst_config_state[i+1].sew;
233	          LMUL1: vlmax[i] = (`VLENB) >> inst_config_state[i+1].sew;
234	          LMUL2: vlmax[i] = (2*(`VLENB)) >> inst_config_state[i+1].sew;
235	          LMUL4: vlmax[i] = (4*(`VLENB)) >> inst_config_state[i+1].sew;
236	          LMUL8: vlmax[i] = (8*(`VLENB)) >> inst_config_state[i+1].sew;
237	          default: vlmax[i] = 0;
238	        endcase
239	
240	        if (inst_config_state[i+1].vill) begin
241	          // If illegal, set to 0. See end of section 6.1 of RVV spec.
242	          inst_config_state[i+1].vl = 0;
243	        end else if (avl[i] > vlmax[i]) begin
244	          // One possible valid impl according to 6.3 of RVV spec.
245	          inst_config_state[i+1].vl = vlmax[i];
246	        end else begin
247	          inst_config_state[i+1].vl = avl[i];
248	        end
249	
250	        inst_config_state[i+1].lmul = inst_config_state[i+1].lmul_orig;
251	
252	        // TODO: filter out illegal lmul for widening ALU ops and non-indexed
253	        // LSU ops where eew>sew.
254	        if (REDUCE_LMUL) begin
255	          // We use vl here, it's guaranteed to be <= vlmax. This operation
256	          // should either reduce lmul or keep it untouched.
257	          // We don't need to worry about eew&emul here:
258	          // - the current sew&lmul is valid (does not lead to emul>8) and
259	          //   we don't increase it, so we cannot generate emul>8.
260	          // - we must keep lmul valid for the current sew, like lmul>=m1 for
261	          //   sew=e32. The resulting enul must also be valid.
262	          vl_minus_one[i] = (inst_config_state[i+1].vl == (`VL_WIDTH)'('b0)) ?
263	              (`VL_WIDTH)'('b0) :
264	              inst_config_state[i+1].vl - (`VL_WIDTH)'('b1);
265	          unique case (inst_config_state[i+1].sew)
266	            SEW8: begin
267	              if (vl_minus_one[i][`VL_WIDTH-2+:2] != 'b00) begin
268	                // vl from VLEN/2+1 to VLEN
269	                inst_config_state[i+1].lmul = LMUL8;
270	              end else if (vl_minus_one[i][`VL_WIDTH-3] == 'b1) begin
271	                // vl from VLEN/4+1 to VLEN/2
272	                inst_config_state[i+1].lmul = LMUL4;
273	              end else if (vl_minus_one[i][`VL_WIDTH-4] == 'b1) begin
274	                // vl from VLEN/8+1 to VLEN/4
275	                inst_config_state[i+1].lmul = LMUL2;
276	              end else if (vl_minus_one[i][`VL_WIDTH-5] == 'b1) begin
277	                // vl from VLEN/16+1 to VLEN/8
278	                inst_config_state[i+1].lmul = LMUL1;
279	              end else if (vl_minus_one[i][`VL_WIDTH-6] == 'b1) begin
280	                // vl from VLEN/32+1 to VLEN/16
281	                inst_config_state[i+1].lmul = LMUL1_2;
282	              end else begin
283	                // vl from 0 to VLEN/32
284	                inst_config_state[i+1].lmul = LMUL1_4;
285	              end
286	            end
287	            SEW16: begin
288	              if (vl_minus_one[i][`VL_WIDTH-3+:2] != 'b00) begin
289	                // vl from VLEN/4+1 to VLEN/2
290	                inst_config_state[i+1].lmul = LMUL8;
291	              end else if (vl_minus_one[i][`VL_WIDTH-4] == 'b1) begin
292	                // vl from VLEN/8+1 to VLEN/4
293	                inst_config_state[i+1].lmul = LMUL4;
294	              end else if (vl_minus_one[i][`VL_WIDTH-5] == 'b1) begin
295	                // vl from VLEN/16+1 to VLEN/8
296	                inst_config_state[i+1].lmul = LMUL2;
297	              end else if (vl_minus_one[i][`VL_WIDTH-6] == 'b1) begin
298	                // vl from VLEN/32+1 to VLEN/16
299	                inst_config_state[i+1].lmul = LMUL1;
300	              end else if (vl_minus_one[i][`VL_WIDTH-7] == 'b1) begin
301	                // vl from VLEN/64+1 to VLEN/32
302	                inst_config_state[i+1].lmul = LMUL1_2;
303	              end else begin
304	                // vl from 0 to VLEN/64
305	                inst_config_state[i+1].lmul = LMUL1_4;
306	              end
307	            end
308	            SEW32: begin
309	              if (vl_minus_one[i][`VL_WIDTH-4+:2] != 'b00) begin
310	                // vl from VLEN/8+1 to VLEN/4
311	                inst_config_state[i+1].lmul = LMUL8;
312	              end else if (vl_minus_one[i][`VL_WIDTH-5] == 'b1) begin
313	                // vl from VLEN/16+1 to VLEN/8
314	                inst_config_state[i+1].lmul = LMUL4;
315	              end else if (vl_minus_one[i][`VL_WIDTH-6] == 'b1) begin
316	                // vl from VLEN/32+1 to VLEN/16
317	                inst_config_state[i+1].lmul = LMUL2;
318	              end else if (vl_minus_one[i][`VL_WIDTH-7] == 'b1) begin
319	                // vl from VLEN/64+1 to VLEN/32
320	                inst_config_state[i+1].lmul = LMUL1;
321	              end else if (vl_minus_one[i][`VL_WIDTH-8] == 'b1) begin
322	                // vl from VLEN/128+1 to VLEN/64
323	                inst_config_state[i+1].lmul = LMUL1_2;
324	              end else begin
325	                // vl from 0 to VLEN/128
326	                inst_config_state[i+1].lmul = LMUL1_4;
327	              end
328	            end
329	          endcase
330	        end
331	      end
332	    end
333	  end
334	
335	  always_ff @(posedge clk or negedge rstn) begin
336	    if (!rstn) begin
337	      // Per Section 3.11 of RVV spec, the recommended state on reset is
338	      // vill is set, with the remain vtype bits and vl being set to 0.
339	      config_state_q.vill <= 1;
340	      config_state_q.vl <= 0;
341	      config_state_q.vstart <= 0;
342	      config_state_q.ma <= 0;
343	      config_state_q.ta <= 0;
344	      config_state_q.xrm <= RNU;
345	      config_state_q.xsat <= 0;
346	`ifdef ZVE32F_ON
347	      config_state_q.frm <= RVFRM'('0);
348	`endif  // ZVE32F_ON
349	      config_state_q.sew <= SEW8;
350	      config_state_q.lmul <= LMUL1;
351	      config_state_q.lmul_orig <= LMUL1;
352	    end else begin
353	      // Update config state next cycle
354	      config_state_q <= inst_config_state[N];
355	    end
356	  end
357	
358	  // Propagate outputs
359	  logic [N-1:0] unaligned_cmd_valid;
360	  RVVCmd [N-1:0] unaligned_cmd_data;
361	  logic [N-1:0] unaligned_trap_valid;  // Should this instruction trap
362	  RVVInstruction [N-1:0] unaligned_trap_data;
363	  always_comb begin
364	    for (int i = 0; i < N; i++) begin
365	      unaligned_trap_valid[i] = valid_inst_q[i] && !is_setvl[i] &&
366	          inst_config_state[i+1].vill;
367	      unaligned_trap_data[i] = inst_q[i];
368	      unaligned_cmd_valid[i] = valid_inst_q[i] && !is_setvl[i] &&
369	          !inst_config_state[i+1].vill;
370	
371	      // Combine instruction + arch state into command
372	`ifdef TB_SUPPORT
373	      unaligned_cmd_data[i].inst_pc = inst_q[i].pc;
374	`endif
375	      unaligned_cmd_data[i].opcode = inst_q[i].opcode;
376	      unaligned_cmd_data[i].bits = inst_q[i].bits;
377	      unaligned_cmd_data[i].arch_state = inst_config_state[i+1];
378	      // TODO: Handle rs propagation for loads/stores
379	      // funct3 == inst[14:12] == bits[7:5]; bits[7] == funct3[2] indicates
380	      // scalar rs1 is used (OPIVX, OPFVF, OPMVX, OPCFG). For OPFVF the scalar
381	      // comes from the floating-point regfile.
382	      unaligned_cmd_data[i].rs1 =
383	          inst_q[i].bits[7] ?
384	              ((inst_q[i].bits[7:5] == 3'b101) ? freg_read_data_i[i]  // OPFVF
385	                                               : reg_read_data_i[2*i])
386	            : 0;
387	
388	      // Write new value of vl into rd for configuration function.
389	      reg_write_valid_o[i] = is_setvl[i];
390	      reg_write_addr_o[i] = inst_q[i].bits[4:0];
391	      reg_write_data_o[i] =
392	          {{(`XLEN-`VL_WIDTH){1'b0}}, inst_config_state[i+1].vl};
393	    end
394	  end
395	
396	  // Align outputs
397	  Aligner#(.T(RVVCmd), .N(N)) cmd_aligner(
398	      .valid_in(unaligned_cmd_valid),
399	      .data_in(unaligned_cmd_data),
400	      .valid_out(cmd_valid_o),
401	      .data_out(cmd_data_o)
402	  );
403	
404	  // Trap
405	  logic trap_occurred;
406	  RVVInstruction trap_data;
407	  assign trap_valid_o = trap_occurred;
408	  assign trap_data_o = trap_data;
409	  always_comb begin
410	    trap_occurred = (unaligned_trap_valid != 0);
411	    // Initialize all trap_data fields to some zero value
412	    trap_data.pc = '0;
413	    trap_data.bits = '0;
414	    trap_data.opcode = RVV;
415	
416	    for (int i = 0; i < N; i++) begin
417	      if (unaligned_trap_valid[i]) begin
418	        trap_occurred = 1'b1;
419	        trap_data = unaligned_trap_data[i];
420	        break;
421	      end
422	    end
423	  end
424	
425	  // Assertions
426	`ifndef SYNTHESIS
427	  logic [N-1:0] lsu_requires_rs1_read;
428	  logic [N-1:0] non_lsu_requires_rs1_read;
429	  logic [N-1:0] requires_rs1_read;
430	  logic [N-1:0] lsu_requires_rs2_read;
431	  logic [N-1:0] non_lsu_requires_rs2_read;
432	  logic [N-1:0] requires_rs2_read;
433	  always_comb begin
434	    for (int i = 0; i < N; i++) begin
435	      // All LSU instructions read from rs1
436	      lsu_requires_rs1_read[i] = (inst_q[i].opcode != RVV);
437	      // Non LSU rs1 check
438	      non_lsu_requires_rs1_read[i] = (inst_q[i].opcode == RVV) && (
439	        (inst_q[i].bits[7:5] == 'b100) ||  // OPIVX
440	        (inst_q[i].bits[7:5] == 'b110) ||  // OPMVX
441	        ((inst_q[i].bits[7:5] == 'b111) && (inst_q[i].bits[24:23] != 2'b11))  // vsetvl and vsetvli
442	      );
443	      requires_rs1_read[i] =
444	          lsu_requires_rs1_read[i] || non_lsu_requires_rs1_read[i];
445	
446	      // Only strided loads/stores (mop=0b10) read rs2
447	      lsu_requires_rs2_read[i] = (inst_q[i].opcode != RVV) &&
448	          (inst_q[i].bits[20:19] == 2'b10);
449	      // vsetvl is only non LSU instruction that reads rs2
450	      non_lsu_requires_rs2_read[i] = (inst_q[i].opcode == RVV) &&
451	          (inst_q[i].bits[7:5] == 3'b111) &&
452	          (inst_q[i].bits[24:18] == 7'b1000000);
453	      requires_rs2_read[i] =
454	          lsu_requires_rs2_read[i] || non_lsu_requires_rs2_read[i];
455	    end
456	  end
457	
458	  always @(posedge clk) begin
459	    for (int i = 0; i < N; i++) begin
460	      assert(!valid_inst_q[i] || !requires_rs1_read[i] ||
461	              reg_read_valid_i[2*i]);
462	      assert(!valid_inst_q[i] || !requires_rs2_read[i] ||
463	              reg_read_valid_i[(2*i) + 1]);
464	    end
465	  end
466	`endif  // not def SYNTHESIS
467	endmodule
